<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
    user-select: none;
  }
  h1 {
    font-size: 1.6rem;
    margin-bottom: 12px;
    color: #e2b857;
    text-shadow: 0 0 20px rgba(226,184,87,0.3);
    letter-spacing: 2px;
  }
  #canvas-wrap {
    position: relative;
    border: 2px solid #333;
