  }
  .mat-btn:hover { transform: translateY(-2px); box-shadow: 0 4px 15px rgba(0,0,0,0.4); }
  .mat-btn.active { border-color: #fff; transform: translateY(-2px); box-shadow: 0 4px 20px rgba(255,255,255,0.15); }

