  #mat-sand.active { box-shadow: 0 0 20px rgba(194,164,78,0.6); }
  #mat-water { background: #3a8fd4; color: #fff; }
  #mat-water.active { box-shadow: 0 0 20px rgba(58,143,212,0.6); }
  #mat-wall { background: #6b6b6b; color: #fff; }
  #mat-wall.active { box-shadow: 0 0 20px rgba(107,107,107,0.6); }
  #mat-acid { background: #7ec840; color: #1a1a2e; }
  #mat-acid.active { box-shadow: 0 0 20px rgba(126,200,64,0.6); }
  #mat-empty { background: #444; color: #ccc; }
  #mat-empty.active { box-shadow: 0 0 20px rgba(100,100,100,0.6); }

  #clear {
    padding: 10px 28px;
    background: #c0392b;
    color: #fff;
    border: 2px solid transparent;
    border-radius: 8px;
    font-size: 0.95rem;
